import os
import numpy as np
from src.infrastructure import config
from src.infrastructure.logger import get_logger

logger = get_logger(__name__)

def load_processed_data():
    """Load the pre-processed NumPy arrays generated by Phase 5."""
    try:
        X = np.load(os.path.join(config.PROCESSED_DATA_DIR, "X.npy"))
        y = np.load(os.path.join(config.PROCESSED_DATA_DIR, "y.npy"))
        
        # Limit the number of samples for CPU tractability in simulation
        if len(X) > config.MAX_TRAIN_SAMPLES:
            logger.info(f"Subsampling dataset from {len(X)} to {config.MAX_TRAIN_SAMPLES} samples for CPU VQC training.")
            
            # Stratified sample if possible, or just take first N (assuming shuffled previously)
            X = X[:config.MAX_TRAIN_SAMPLES]
            y = y[:config.MAX_TRAIN_SAMPLES]
            
        logger.info(f"Loaded {len(X)} processed samples: X shape {X.shape}, y shape {y.shape}")
        return X, y
    except FileNotFoundError:
        logger.error("Processed data not found! Run 'python data/generate_dataset.py' first.")
        raise
